) VALUES (
    'c306b7bb-16a9-4cf1-a1e5-2924febda1a4',
    '스트레스가 많을 때 어떻게 해요?',
    'blog-post',
    '<p><span style="font-family: courier;"></span></p><div class="separator" style="clear: both; text-align: center;"><span style="font-family: courier;"><a href="https://blogger.googleusercontent.com/img/b/R29vZ2xl/AVvXsEgE7cGNsulYBhA9FK826U2_vJXI4h0oHia_WUwaRM8WeuSRmLl6DT_eM1PGmbZF5SoPEHZc27akhLliLGrdYmj5oha3LHiuxoNDAbUKxMhSvrfvrwB7QQ-F3xc1TmN3IstcIbL3fTxQcMs/s770/img.jpeg" style="margin-left: 1em; margin-right: 1em;"><img border="0" data-original-height="513" data-original-width="770" height="266" src="https://blogger.googleusercontent.com/img/b/R29vZ2xl/AVvXsEgE7cGNsulYBhA9FK826U2_vJXI4h0oHia_WUwaRM8WeuSRmLl6DT_eM1PGmbZF5SoPEHZc27akhLliLGrdYmj5oha3LHiuxoNDAbUKxMhSvrfvrwB7QQ-F3xc1TmN3IstcIbL3fTxQcMs/w400-h266/img.jpeg" width="400" /></a></span></div><span style="font-family: courier;"><br /></span><span style="font-family: courier;">어른이 된다는 것은 스트레스가 많지요? 어른이란 뭐에요? 저는 어렸을 때 어른이들이 정말 대단해 보였어요. 하지만 나이가 들면서 보니 어른이 된다는 것이 힘들어요. 일이 아주 많아서&nbsp;자신을 위한 시간이 없어요. 그리고&nbsp;스트레스를 받아요.&nbsp;스트레스가 건강 안 좋아요. 여러분은&nbsp;스트레스가 많을 때 어떻게 해요? 저는 스트레스가&nbsp;많을 때는 이렇게 해요. 첫째, 취미 할동을 해요. 제 취미는 많아요: 책을 읽고,&nbsp;언어를 공부고, 강아지와 산책해요.바람을 쇠려고 산책하고&nbsp;</span><span style="font-family: courier;">책을 읽은후에 기분이 전환을 해요.&nbsp;</span><span style="font-family: courier;">우리가 좋아하는 것을하면,&nbsp;스트레스가 풀릴 거에요.&nbsp;</span><span style="font-family: courier;">여러분은 무슨 일을 좋아해요? 그 일을 해 보세요. 사람들은 친구하고 수다를 떨은 것을 보통 좋아하지만 저는&nbsp;</span><span style="font-family: courier;">혼자있는 것이 좋아요. 저는 시끄러운 장소를 안 좋아요.&nbsp;</span><span style="font-family: courier;">둘째, 운동을 해요. 하지만 너무 함든 운동을 하지 마세요. 저는 매주 테니스를 쳐요. 노무 즐거워요.&nbsp;</span><span style="font-family: courier;">테니스를 친 후에&nbsp; 건강 해져요. 그리고 더 기뻐요. 저는&nbsp;</span><span style="font-family: courier;">테니스를 잘 못 쳐서 아직 배워요.&nbsp;</span><span style="font-family: courier;">하지만 코로나&nbsp;때문에 테니스를 치기가 조금 무서워해요.&nbsp;지금 테니스를 그만둬요.&nbsp;코로나 19펜데믹이 끝나면 다시 칠 거에요. 셋째, 푹 잘고 쉬세요.&nbsp;오늘은 여기까지예요! 감사합니다.</span><p></p><div><span style="font-family: courier;"><br /></span></div><div><span style="font-family: courier;">** Please kindly revise if I made any mistake..</span></div>',
    '어른이 된다는 것은 스트레스가 많지요? 어른이란 뭐에요? 저는 어렸을 때 어른이들이 정말 대단해 보였어요. 하지만 나이가 들면서 보니 어른이 된다는 것이 힘들어요. 일이 아주 많아서&nbsp;자신을 위한 시간이 없어요. 그리고&nbsp;스트레스를 받아요.&nbsp;스트레스가 건강 안 좋아요. 여러분은&nbsp;스트레스가 많을 때 어떻게 해요?',
    NULL,
    'language',
    ARRAY['language'],
    3,
    NULL,
    '{"image_url":"https://blogger.googleusercontent.com/img/b/R29vZ2xl/AVvXsEgE7cGNsulYBhA9FK826U2_vJXI4h0oHia_WUwaRM8WeuSRmLl6DT_eM1PGmbZF5SoPEHZc27akhLliLGrdYmj5oha3LHiuxoNDAbUKxMhSvrfvrwB7QQ-F3xc1TmN3IstcIbL3fTxQcMs/w400-h266/img.jpeg"}',
    false,
    false,
    true,
    '2021-06-26T14:09:00.009Z',
    '2021-06-26T12:11:26.176Z',
    '2021-06-26T14:40:24.806Z'
);

INSERT INTO posts (
    id, title, slug, content, excerpt, pull_quote, category, tags,
