    ARRAY['slider', 'science'],
    8,
    NULL,
    '{"image_url":"https://blogger.googleusercontent.com/img/b/R29vZ2xl/AVvXsEgieXZo4iRk5jryGSPw4E5LNt-7CnQCY2chdBAKUVplU-QQDMyb50SbPdsOH8xFsRzhHLj42kGh-inI_KWNZC9l04nZ2Xbf9R_VdJi2XgLd_QUECqP_JjGTbNAxU3EV81pA8X1zeaR_h3M/s16000/cover.jpeg"}',
    false,
    false,
    true,
    '2021-05-26T06:52:00.003Z',
