);

INSERT INTO posts (
    id, title, slug, content, excerpt, pull_quote, category, tags,
    read_time, issue, cover_art, text_only, featured, published,
    published_at, created_at, updated_at
) VALUES (
    'd7d1f19e-2da5-4c93-9c88-0642f701d896',
    'How Religion Matters to Me',
    'how-deism-matters-to-me',
    '<span style="font-family: &quot;trebuchet ms&quot; , sans-serif;">In my early 20s, I think a lot about how I want my life to be.&nbsp;I think a lot about what values I want to hold on to, what goals I want to achieve, and what I want to believe in my life. I''m writing about the last one.</span><br />\n<span style="font-family: &quot;trebuchet ms&quot; , sans-serif;"><br /></span>\n<span style="font-family: &quot;trebuchet ms&quot; , sans-serif;">Beliefs. Religions.&nbsp;</span><span style="font-family: &quot;trebuchet ms&quot;, sans-serif;">We''ve seen how religions become a competition. Religious people compete to be the truest. Only in their religion people will find the eternal happiness, eternal peace.. heaven, they said. Religions then become confrontations. Jews and Muslims become enemies. Churches burned and bombed. People murdered for being atheists. &nbsp;As everyday unfolds, I see more.. and I just don''t like what I see. </span><span style="font-family: &quot;trebuchet ms&quot;, sans-serif;"><b>The most lasting effect of religion on the human race is that it has been the cause of almost every war since the beginning of time.</b> With one religion thinking it is the "true" religion over all others, what other result could there be?</span><br />\n<span style="font-family: &quot;trebuchet ms&quot; , sans-serif;"><br /></span>\n\n<span style="font-family: &quot;trebuchet ms&quot; , sans-serif;">Another side.&nbsp;Religion helps to keep people from feeling fear of the unknown. Many of those who are in despair, afraid, hopeless, and miserable revived and healed thanks to religion.&nbsp;There are those people who cling to religion of some kind because they cannot bear to think that this world was not made by a creator, or God. It shakes their world to think that they have been placed here without a safety net, so to speak. Well, maybe I''m one of those people, I believe in that safety net.</span><br />\n<br />\n\n<span style="font-family: &quot;trebuchet ms&quot; , sans-serif;">So.. I''m neither an atheist nor a secular humanist.&nbsp;</span><br />\n<span style="font-family: &quot;trebuchet ms&quot; , sans-serif;">I believe in the existence of God.</span><br />\n<span style="font-family: &quot;trebuchet ms&quot; , sans-serif;"><br /></span>\n<span style="font-family: &quot;trebuchet ms&quot; , sans-serif;">How about clinging to organized religions?</span><br />\n<span style="font-family: &quot;trebuchet ms&quot; , sans-serif;">My two cents, the only problem comes when you organize these beliefs into religions... then you get the conflicts that lead to violence and real evil. Imagine&nbsp;if we removed organized religion, there would be no "them" to fight against. People can believe whatever they want about gods and sons of gods, it just doesn''t have to lead to violence because beliefs do not have to be organized into official monoliths and defended. Resist organized religion, and you resist one of the greatest forces of evil in history.</span><br />\n<br />\n<span style="font-family: &quot;trebuchet ms&quot; , sans-serif;">Actually&nbsp;to this day, religion for the most part is still based on fear. Religion tells people to do and don''t do things or else there will be a ''retribution''. This God was never a very forgiving one. Well, as long as it leads people to do the right things I think it''s fine. Personally for me, I don''t want to do anything based on fear, I want to do things because of what I am. I want it to be based on sympathy, empathy, humanity. We don''t need fear to do good deeds.</span><br />\n<br />\n<span style="font-family: &quot;trebuchet ms&quot; , sans-serif;">A friend said to me that it would do no good to eradicate religion. He said "then they''d just kill each other in the name of something else. Like which football team they support?". I still think we would be better. Football teams do not force upon people any particular intellectual framework, nor link it to moral theory. <b>The fact that religions claim divinity, that they claim absolute truth and link morality, society, authority and philosophy all into one whole, makes people more likely to fight and die for them.&nbsp;</b></span><br />\n<span style="font-family: &quot;trebuchet ms&quot; , sans-serif;"><br /></span>\n<span style="font-family: &quot;trebuchet ms&quot; , sans-serif;">Religion causes crimes, mass murders, suicide cults.. I know it depends on the people, not on the religion, and the fact that not all religious people do bad things.. but isn''t if there''s no religion things would be better? Why should I believe in these things? Aren''t these things are made by us human?</span><br />\n<span style="font-family: &quot;trebuchet ms&quot;, sans-serif;"><br /></span>\n<span style="font-family: &quot;trebuchet ms&quot;, sans-serif;">I believe in God, &nbsp;but I don''t believe in organized religions. Sometimes I thought religions are bad for our intelligence.. haha. Newton and Einstein may have disagreed, but they refrained from violently attacking each other''s followers. Atheists and scientists do not kill each other over their beliefs. :p</span><br />\n<div>\n<span style="font-family: &quot;trebuchet ms&quot; , sans-serif;"><br /></span></div>\n<div>\n<span style="font-family: &quot;trebuchet ms&quot; , sans-serif;"><br /></span></div>\n<br />\n<br />\n<span style="font-family: &quot;trebuchet ms&quot; , sans-serif;"><br /></span>\n<span style="font-family: &quot;trebuchet ms&quot; , sans-serif;"><br /></span>\n<span style="font-family: &quot;trebuchet ms&quot; , sans-serif;"><br /></span>\n<span style="font-family: &quot;trebuchet ms&quot; , sans-serif;"><br /></span>\n<br />\n<br />\n<br />\n<span style="font-family: &quot;trebuchet ms&quot; , sans-serif;"><br /></span>\n<span style="font-family: &quot;trebuchet ms&quot; , sans-serif;"><br /></span>\n<span style="font-family: &quot;trebuchet ms&quot; , sans-serif;"><br /></span>\n<span style="font-family: &quot;trebuchet ms&quot; , sans-serif;"><br /></span>\n<span style="font-family: &quot;trebuchet ms&quot; , sans-serif;"><br /></span>\n<span style="font-family: &quot;trebuchet ms&quot; , sans-serif;"><br /></span>\n<span style="font-family: &quot;trebuchet ms&quot; , sans-serif;"><br /></span>\n',
    'In my early 20s, I think a lot about how I want my life to be.&nbsp;I think a lot about what values I want to hold on to, what goals I want to achieve, and what I want to believe in my life.',
    'The most lasting effect of religion on the human race is that it has been the cause of almost every war since the beginning of time.',
    'perspective',
    ARRAY['perspective', 'personal', 'other'],
    4,
    NULL,
    '{"p1":"#6f9bd1","p2":"#c08a64"}',
    false,
    false,
    true,
    '2013-01-07T15:28:00Z',
    '2013-01-07T12:08:24.052Z',
    '2017-06-02T05:09:09.867Z'
);

INSERT INTO posts (
    id, title, slug, content, excerpt, pull_quote, category, tags,
    read_time, issue, cover_art, text_only, featured, published,
    published_at, created_at, updated_at
) VALUES (
    'bd951203-d412-458b-828d-d0c8ca9b3d6d',
    'Chinese on London Olympics 2012',
    'chinese-on-london-olympics-2012',
    '<div class="separator" style="clear: both; text-align: center;">\n<br /></div>\n<span class="Apple-style-span" style="font-family: inherit;">It''s been quite a long time since my last post, I''ve been made busy by my daily work, thesis preparation, and several website projects I''m into. But I''m back now! I want to write a lot about the London Olympics 2012 (including weird athletes'' bodies noticed , badminton cheating, Tom Daley''s case, &nbsp;and not to forget about how fun and glamorous the opening ceremony is !); but this first post will focus on how Chinese athletes are&nbsp;ridiculously&nbsp;brilliant in seemingly everything.&nbsp;</span><br />\n<span class="Apple-style-span" style="font-family: inherit;"><br /></span><span class="Apple-style-span" style="font-family: inherit;">We''ve known from the very beginning, living in China is really competitive. Since the number of population is very high (</span><span class="Apple-style-span" style="font-family: inherit; line-height: 19px;">over 1.3 billion</span><span class="Apple-style-span" style="font-family: inherit;">), they are all trying very hard to stand out from others and reach their own goals.</span><br />\n<br />\n<span class="Apple-style-span" style="font-family: inherit;">Several weeks ago, I read an article on the morning newspaper about Chinese high school graduates'' extreme efforts to enter universities. Universities in China offer a limited number of available seats (less than 7 million seats) while the number of applicants is more than 9 million. Some of them hooked up to oxygen canisters and intravenous drips of amino acids during late-night and weekend study marathons. Girls take&nbsp;</span>contraception<span class="Apple-style-span" style="font-family: inherit;">&nbsp;and hormone shots to prevent having their period during the entrance exam. Parents hired special tutors and forced their children into educational boot camps.</span><span class="Apple-style-span" style="font-family: inherit;">&nbsp;Hotels nearby to universities were fully booked and nannies were hired to take care of the applicants.That''s pretty much about it. The whole country is in on it.</span><br />\n<span class="Apple-style-span" style="font-family: inherit;"><br /></span>\n<span class="Apple-style-span" style="font-family: inherit;">It''s no surprise that Chinese excel in almost everything, should I say? They train and study really hard for everything. Talking about the London Olympics 2012, just how far will the Chinese go to win golds?</span><br />\n<span class="Apple-style-span" style="font-family: inherit;"><br /></span>\n<br />\n<table align="center" cellpadding="0" cellspacing="0" class="tr-caption-container" style="margin-left: auto; margin-right: auto; text-align: center;"><tbody>\n<tr><td style="text-align: center;"><a href="http://i.dailymail.co.uk/i/pix/2012/08/01/article-0-145294BB000005DC-973_634x465.jpg" imageanchor="1" style="margin-left: auto; margin-right: auto;"><img border="0" src="http://i.dailymail.co.uk/i/pix/2012/08/01/article-0-145294BB000005DC-973_634x465.jpg" height="234" width="320" /></a></td></tr>\n<tr><td class="tr-caption" style="text-align: center;"><span style="background-color: white; font-family: &quot;arial&quot; , &quot;helvetica&quot; , sans-serif; font-size: 10px; text-align: left;">Gymnastic stars are known for starting at an incredibly early age</span><span style="font-family: &quot;arial&quot; , &quot;helvetica&quot; , sans-serif; font-size: 10px; text-align: left;"><br /></span></td></tr>\n</tbody></table>\nAs everyone may have known, Ye Shiwen, the Chinese female swimmer is called a super girl after her record-breaking-swim on Saturday. She beats the US men''s final champion&nbsp;Ryan Lochte&nbsp;for the last 50 m and knocked off her personal record by 5 seconds. People called the swim incredible, but also ''disturbing''.<br />\nU.S attacked her for for using drugs during the swim. All she said was just "It''s all purely from hard work and training", which I may believe. (Ye''s team-mate, 23-year-old Lu Ying, this week attacked China''s grindingly repetitive coaching regime)<br />\n<br />\nAnother story is about the Chinese diver Wu Minxia. She&nbsp;made history at the 2012 London Olympics after placing first in the women''s synchronized 3-meter springboard competition on Sunday, becoming the first female diver to win gold in the same event for three consecutive Olympics.&nbsp;However, shock soon followed her momentous achievement, when her father revealed details of a family life kept secret to the 26-year-old athlete for years. Her mother has cancer and her grandmother has died. The facts have been hidden from her for years in order to keep her focusing on the&nbsp;Olympic. It''s just sad. If I were her, I would prefer to be told about the facts before it''s too late, who knows if her mother could have just died before she won the gold and she had no opportunity to meet her because of the hard training.<br />\n<br />\nI searched the web about Chinese training camps and found many horrible stuffs.. I just want to share them here. Take a look :<br />\n<br />\n<table cellpadding="0" cellspacing="0" class="tr-caption-container" style="margin-left: auto; margin-right: auto; text-align: center;"><tbody>\n<tr><td style="text-align: center;"><a href="http://i3.mirror.co.uk/incoming/article1196740.ece/ALTERNATES/s615b/A+young+Chinese+gymnast+in+training+being+stretched" imageanchor="1" style="clear: right; margin-bottom: 1em; margin-left: auto; margin-right: auto;"><img border="0" src="http://i3.mirror.co.uk/incoming/article1196740.ece/ALTERNATES/s615b/A+young+Chinese+gymnast+in+training+being+stretched" height="320" width="226" /></a></td></tr>\n<tr><td class="tr-caption" style="text-align: center;">I don''t want my children to be treated this way even if it''s for gold medal</td></tr>\n</tbody></table>\n<table align="center" cellpadding="0" cellspacing="0" class="tr-caption-container" style="margin-left: auto; margin-right: auto; text-align: center;"><tbody>\n<tr><td style="text-align: center;"><a href="http://i.dailymail.co.uk/i/pix/2012/07/31/article-0-144C2E95000005DC-672_634x323.jpg" imageanchor="1" style="margin-left: auto; margin-right: auto;"><img border="0" src="http://i.dailymail.co.uk/i/pix/2012/07/31/article-0-144C2E95000005DC-672_634x323.jpg" height="203" width="400" /></a></td></tr>\n<tr><td class="tr-caption" style="text-align: center;">hard training and punishments are made to toughen the children up</td></tr>\n</tbody></table>\n<table align="center" cellpadding="0" cellspacing="0" class="tr-caption-container" style="margin-left: auto; margin-right: auto; text-align: center;"><tbody>\n<tr><td style="text-align: center;"><a href="http://i.dailymail.co.uk/i/pix/2012/07/31/article-0-14303879000005DC-298_634x371.jpg" imageanchor="1" style="margin-left: auto; margin-right: auto;"><img border="0" src="http://i.dailymail.co.uk/i/pix/2012/07/31/article-0-14303879000005DC-298_634x371.jpg" height="187" width="320" /></a></td></tr>\n<tr><td class="tr-caption" style="text-align: center;">children are trained at camps where the word ''gold'' is hung on the wall to make them focus on success</td></tr>\n</tbody></table>\n<br />\n<table align="center" cellpadding="0" cellspacing="0" class="tr-caption-container" style="margin-left: auto; margin-right: auto; text-align: center;"><tbody>\n<tr><td style="text-align: center;"><a href="http://i.dailymail.co.uk/i/pix/2012/08/01/article-0-145294AB000005DC-827_634x800.jpg" imageanchor="1" style="margin-left: auto; margin-right: auto;"><img border="0" src="http://i.dailymail.co.uk/i/pix/2012/08/01/article-0-145294AB000005DC-827_634x800.jpg" height="320" width="252" /></a></td></tr>\n<tr><td class="tr-caption" style="text-align: center;">A gymnastic trainer stands on a child etching with pain<br />\n<br /></td></tr>\n</tbody></table>\n<div class="separator" style="clear: both; text-align: center;">\n</div>\n<br />\nRuthless.. Well, it''s China.<br />\n<div>\n<br /></div>\n<div>\n<br /></div>\n<div>\nNote : this post was written during the olympics, I forgot to publish it until now :p<br />\n<br /></div>\n',
    'It''s been quite a long time since my last post, I''ve been made busy by my daily work, thesis preparation, and several website projects I''m into. But I''m back now!',
    'Gymnastic stars are known for starting at an incredibly early age',
    'others',
    ARRAY['chinese', 'training', 'sport', 'culture'],
    4,
    NULL,
    '{"image_url":"http://i.dailymail.co.uk/i/pix/2012/08/01/article-0-145294BB000005DC-973_634x465.jpg"}',
    false,
    false,
    true,
    '2012-12-25T10:36:00Z',
    '2012-08-02T09:07:04.298Z',
    '2017-06-02T06:03:21.922Z'
);

INSERT INTO posts (
    id, title, slug, content, excerpt, pull_quote, category, tags,
    read_time, issue, cover_art, text_only, featured, published,
    published_at, created_at, updated_at
) VALUES (
    'd7d19cb4-3871-40b8-a5db-c78bf3fd350f',
    'How Twitter Makes Money',
    'how-twitter-makes-money',
    'On our Facebook homepage, we could see a sidebar full for advertisements. We know where it ends : more money for Facebook. How about Twitter? Twitter seems to have no advertisement, our homepage is clean from company logos and promotional words. How does Twitter make money ?<br />\n<br />\nLets watch this video :<br />\n<br />\n<iframe allowfullscreen="" frameborder="0" height="360" src="https://www.youtube.com/embed/iW2Oal1ybgM?feature=player_embedded" width="640"></iframe><br />\n<br />\nYes, Twitter makes money from its ''Promoted'' products. Here is a quick breakdown of a number of ways Twitter takes to make its money (including its ''Promoted'' products) :<br />\n<a href="http://www.techhail.org/wp-content/uploads/2010/06/Twitter-Rolls-Out-Promoted-Trending-Topics-After-Promoted-Tweets-to-Make-Money.jpg" imageanchor="1" style="clear: right; float: right; margin-bottom: 1em; margin-left: 1em;"><img border="0" src="http://www.techhail.org/wp-content/uploads/2010/06/Twitter-Rolls-Out-Promoted-Trending-Topics-After-Promoted-Tweets-to-Make-Money.jpg" height="217" width="320" /></a><a href="http://anthonyjlockhart.files.wordpress.com/2011/04/twitter-royalwedding.png" imageanchor="1" style="clear: right; float: right; margin-bottom: 1em; margin-left: 1em;"><img border="0" src="http://anthonyjlockhart.files.wordpress.com/2011/04/twitter-royalwedding.png" height="200" width="128" /></a><br />\n<br />\n<br />\n<br />\n<br />\n<li><span style="background-color: #ffe599;">Promoted Tweets</span><br />Promoted tweets are called out at the top of relevant search results. Brands or partners with enhanced profile pages (we''ll talk about this later) may also choose to pin a Promoted Tweet to the top of their timelines. Promoted tweets are cost-per-click ads.<br /><br />Just a couple examples, Disney/Pixar did this to promote Toy Story 3. And when the Google I/O conference was taking place, they also tweeted about 100 conference tickets left ($550 bucks/ticket). The tickets were sold out within 11 minutes. Wow.<br /><span style="background-color: #ffe599;"><br /></span></li>\n<li><span style="background-color: #ffe599;">Promoted Trends</span>Promoted trends appear at the top of trending topic lists. This daily sponsorship drives huge amount of impressions, engagements (replies, retweets, and tweets about it), and clicks. But, it requires a large financial commitment.</li>\n<li><span style="background-color: #ffe599;">Promoted Accounts</span><br />Promoted accounts are part of <b>Who To Follow </b>widget on the left side of our homepage. You&nbsp;may see a Promoted Account as one of the suggestions if a Promoted Account is relevant for you.&nbsp;As with Promoted Trends and Promoted Tweets, this suggestion is labeled as Promoted to distinguish it from other recommended accounts.&nbsp;Promoted Accounts are suggested based on a user’s public list of whom they follow.</li>\n<li><span style="background-color: #ffe599;">Political Ads</span><br />Political ads are run by candidates or persons/committees&nbsp;who are advocating for election or defeat of a political candidate. These ads may include Promoted Tweets, Accounts, or Trends.</li>\n<li><span style="background-color: #ffe599;">Enhanced Profile Pages</span><br />Enhanced profile pages will display a 835 x 90 pixel header image right below the account information. As stated above, users with enhanced profile pages may pin a promoted tweets to the top of their timelines.<br /></li>\n<li><span style="background-color: #ffe599;">Search Engines</span><br />Google, Yahoo, and Microsoft''s bing pay Twitter so that they can include tweets in their real-time search results.</li>\n<br />\n<br />',
    'On our Facebook homepage, we could see a sidebar full for advertisements. We know where it ends : more money for Facebook. How about Twitter?',
    NULL,
    'others',
    ARRAY['advertisement', 'twitter', 'technology', 'money'],
    3,
    NULL,
    '{"image_url":"http://www.techhail.org/wp-content/uploads/2010/06/Twitter-Rolls-Out-Promoted-Trending-Topics-After-Promoted-Tweets-to-Make-Money.jpg"}',
    false,
    false,
    true,
    '2012-06-17T03:01:00.002Z',
    '2012-06-17T01:21:25.935Z',
    '2017-06-02T06:01:49.644Z'
);

INSERT INTO posts (
    id, title, slug, content, excerpt, pull_quote, category, tags,
    read_time, issue, cover_art, text_only, featured, published,
    published_at, created_at, updated_at
) VALUES (
    '60e43f36-b8db-4ced-bb70-8739907f31ed',
    'Why British Love Their Queen',
    'why-british-love-their-queen',
    '<iframe allowfullscreen="" frameborder="0" height="360" src="http://www.youtube.com/embed/R2grMaRttws?feature=player_embedded" width="640"></iframe><br />\n<br />\nHave you watched the video? As I said on the older post, The Queen famously learned to drive and even served as a mechanic during World War II.&nbsp;She’s the only ever British monarch who had been trained to change a spark plug. I think she''s cool.<br />\n<br />\nThe fact is, she should not, in the normal course of events have become queen.<br />\n<br />\n<div class="separator" style="clear: both; text-align: center;">\n<a href="https://blogger.googleusercontent.com/img/b/R29vZ2xl/AVvXsEiZVQELtYQryOcF8Rt5Ab35aEJQTqgpHpaOF4wbUOU3beMbnHxjo2UHMTUB_pY7SwV1w5L5d_gNZ3qHYK4YPYW4LjNUelVAcTE8qnA-5qyvCh19LjjH7zRqTquAXSW_soOZzfK1P1QTPRx1/s1600/Royal_Family.jpg" imageanchor="1" style="clear: left; float: left; margin-bottom: 1em; margin-right: 1em;"><img border="0" height="222" src="https://blogger.googleusercontent.com/img/b/R29vZ2xl/AVvXsEiZVQELtYQryOcF8Rt5Ab35aEJQTqgpHpaOF4wbUOU3beMbnHxjo2UHMTUB_pY7SwV1w5L5d_gNZ3qHYK4YPYW4LjNUelVAcTE8qnA-5qyvCh19LjjH7zRqTquAXSW_soOZzfK1P1QTPRx1/s320/Royal_Family.jpg" width="320" /></a></div>\nElizabeth Alexandra Mary, born 21 April 1926,&nbsp;was the first child of Prince Albert. Please note that Prince Albert is the <b>second</b> son of king George V. Yup, Prince Albert was not heir to the throne, in the normal course of events.<br />\n<br />\nOn the death of Queen Victoria in 1901, Albert''s grandfather became King Edward VII.<br />\nLater in&nbsp;1910, his father became King George V. &nbsp;Then, as expected, Albert''s elder brother (Edward) became King Edward VIII.<br />\n<br />\nKing Edward VIII was known to&nbsp;disappoint&nbsp;his father&nbsp;because&nbsp;of his failure to settle down in life and appalled by his many affairs with married woman. In contrary, his father fancied Prince Albert and doted on his eldest granddaughter, Elizabeth.<br />\n<br />\nI cited this from Wikipedia &nbsp;:<br />\n<blockquote class="tr_bq">\n<i>At the procession to George V''s Lying in State in Westminster Hall, part of the Imperial State Crown fell from on top of the coffin and landed in the gutter as the cortège turned into New Palace Yard. The new king, Edward VIII, saw it fall and wondered whether it was a bad omen for his new reign. Edward would abdicate before the year was out, leaving Albert, to ascend the throne , taking the title George VI</i> (Many said Edward VIII preferred the woman he loved to the crown of the Realm).</blockquote>\n<br />\nSo that''s how Elizabeth''s father became king (FYI, he had a stammer and was forced to write with right hand though he was left-handed).&nbsp;Two years later after his coronation, the United Kingdom was at war with NAZI and this nervous and mild mannered man somehow boosted the morale of his country. Radio broadcasts brought his voice into homes, he spoke as a man of faith, integrity and courage.<br />\n<br />\nGeorge VI and his wife resolved to stay in London, despite German bombing raids.&nbsp;Throughout the war, the King and Queen provided morale-boosting visits throughout the United Kingdom, visiting bomb sites, munitions factories, and comforted the injured and homeless.<br />\n<br />\nBuckingham Palace received a direct bomb hit.The King and Queen escaped being badly wounded by glass. Their identification with the suffering of ordinary men and women resulted in a warm response from their subjects.&nbsp;In 1945, crowds shouted "We want the King!" in front of Buckingham Palace during the Victory in Europe Day celebrations.&nbsp;When the King died of cancer in 1952, the nation took his 26 year old grieving daughter to their hearts. She did not disappoint them.<br />\n<br />\nQueen Elizabeth II is a really hardworking and remarkable woman.<br />\n<br />\n<br />\n<div class="separator" style="clear: both; text-align: center;">\n</div>\n1. Although it is known that she is not very comfortable with appearing on television nevertheless she does this every Christmas as she delivers her personal message to the nation. She is frequently seen attending a huge variety of functions around the country and around the world.<br />\n<br />\n<br />\n2. She must have experienced personal sadness in her life , but none of us has a clue what the Queen thinks, throughout the difficult times.She endured them herself. The only time anyone has ever seen her show any emotion was when she called &nbsp;1992 her annus horribilis (horrible year). During that year many sad things happened. She had to watch her children''s&nbsp;unsuccessful&nbsp;marriages (his son Andrew divorced, her daughter Anne too).&nbsp;Not to mention she was thrown eggs by angry demonstrators during her visit in Germany in the same year; and in November Windsor Castle suffered severe fire damage. The monarchy received increased criticism and public scrutiny. It was just sad.<br />\n<br />\nI cited this from ExpertColumn :<br />\n<br />\n<blockquote class="tr_bq">\n<i>&nbsp;Her children have not led the protected and private life that was hers and any misdemeanours have been publicised for public consumption. Three of her four children have had unhappy marriages with much scandal evolving around the heir to the throne. Diana, Charles’ ex wife and mother of his two sons, died tragically in a car accident. The reaction of the public to this event put much strain on the Royal Family and even the Queen. She saw her third child, Andrew, go to war in the Falklands as a helicopter pilot.</i></blockquote>\n<br />\nBut still, she''s at once uniquely familiar and entirely unknowable. she’d never do anything as frivolous as get teary, angry or upset in public, she’s got an empire to oversee.<br />\n<div>\n<br /></div>\n<div>\n<br /></div>\n<div>\n<a href="http://upload.wikimedia.org/wikipedia/commons/thumb/9/9e/Elizabeth_and_Philip_1953.jpg/220px-Elizabeth_and_Philip_1953.jpg" imageanchor="1" style="clear: left; float: left; margin-bottom: 1em; margin-right: 1em;"><img border="0" src="http://upload.wikimedia.org/wikipedia/commons/thumb/9/9e/Elizabeth_and_Philip_1953.jpg/220px-Elizabeth_and_Philip_1953.jpg" height="320" width="219" /></a>3. Queen and Prince Phillips remind the Brits of the past. The older generation have fond memories of watching their Princess marry her Prince, become a mother and then a Queen. As she had children, so did they. When her aged mother died they mourned with her. In addition, they are a part of British long tradition, can you really leave it just like that? United Kingdom with ... no kingdom?&nbsp;&nbsp;</div>\n<div>\n<br /></div>\n<div>\n<br /></div>\n<div>\n<div class="separator" style="clear: both; text-align: center;">\n</div>\n4. She is funny and sweet, really.<br />\n<ul>\n<li>According to Prince Charles, she used to practice walking around in her coronation crown by wearing it around the palace ; including when she came to see him when he was being bathed as a child.</li>\n<br />\n<li> She took her dog (Susan) on honeymoon with her.</li>\n<br />\n<li> She only stopped horse riding last year aged 84! You naughty Queen! Lol.</li>\n<br />\n<li> Do not forget how badass she was when being a driver and a mechanic ;)</li>\n</ul>\n</div>\n<span style="background-color: #ffe599;"><br /></span>\n<span style="background-color: #ffe599;">So, despite a lot of people saying the Queen''s only a money grabbing person, I think she really has taken her role seriously from the beginning and continues to pledge herself to serve the country.&nbsp;This she does with&nbsp;vigor&nbsp;and energy in spite of her age. We have watched her grow old and her hair turn white but to us she is still the beautiful Queen.&nbsp;She also went through hard times with her family and work; seeing people saying "<i>It is unnecessary and a drain on our resources</i>" is just really sad :(</span><br />\n<br />\nYou know, the tourism facto is a big deal.&nbsp;The Diamond Jubilee itself is expected to send £10 billion ($15 billion) to the British economy via tourism. I hope this post may change your opinion about the Queen.<br />\n<br />\nOnly 26 percent of people think there will be a monarchy in 100 years time, the AP reports, and many believe that a reign by Queen Elizabeth''s son, Charles, would be deeply unpopular.&nbsp;<b>Sadly, they may well be the last ebb of the Royals. So please, make it worth.</b><br />\n<br />\n\n<b><br /></b>\n<span style="background-color: white; font-size: large;">They are national treasures, it wouldn''t look right without them :(</span><br />\n<b><br /></b>\nShould I sing it now ?&nbsp;‘the sweetest Queen the world’s ever seen....who belongs to you and me..''<br />\n<b>''long live our noble Queen, long may she reign over us....God save the Queen.’</b><br />\n<br />\n<br />\n<br />\n<br />\n<br />\n<br />\n<br />\n<br />\n<br />\n<br />\n<br />',
    'Have you watched the video?',
    'They are national treasures, it wouldn''t look right without them :(',
    'others',
    ARRAY['british', 'monarchy', 'history', 'government', 'elizabeth II'],
    6,
    NULL,
    '{"image_url":"https://blogger.googleusercontent.com/img/b/R29vZ2xl/AVvXsEiZVQELtYQryOcF8Rt5Ab35aEJQTqgpHpaOF4wbUOU3beMbnHxjo2UHMTUB_pY7SwV1w5L5d_gNZ3qHYK4YPYW4LjNUelVAcTE8qnA-5qyvCh19LjjH7zRqTquAXSW_soOZzfK1P1QTPRx1/s320/Royal_Family.jpg"}',
    false,
    false,
    true,
    '2012-06-12T15:36:00.001Z',
    '2012-06-12T12:58:33.338Z',
    '2017-06-02T06:00:27.145Z'
);

INSERT INTO posts (
    id, title, slug, content, excerpt, pull_quote, category, tags,
    read_time, issue, cover_art, text_only, featured, published,
    published_at, created_at, updated_at
) VALUES (
    '4761c9b7-8720-4a66-bad9-c1f8a98ceae2',
    'Queen Elizabeth II''s Diamond Jubilee : Loves and Hatreds',
    'queen-elizabeth-iis-diamond-jubilee',
    '<br />\n<div class="separator" style="clear: both; text-align: center;">\n<a href="http://i.telegraph.co.uk/multimedia/archive/02207/qu_2207460b.jpg" imageanchor="1" style="clear: left; float: left; margin-bottom: 1em; margin-right: 1em;"><img border="0" src="http://i.telegraph.co.uk/multimedia/archive/02207/qu_2207460b.jpg" height="125" width="200" /></a></div>\nBeing the head of The Commonwealth of Nations (also known as The British Commonwealth), the head of constitutional monarch of 16 sovereign states known as the Commonwealth realms, and also the head of state of the Crown Dependencies and British Overseas Territories, Queen Elizabeth II has just celebrated her 60th year of throne last week. Yes! The Diamond Jubilee celebration.<br />\n<div class="separator" style="clear: both; text-align: center;">\n</div>\n<div class="separator" style="clear: both; text-align: center;">\n<a href="http://l3.yimg.com/bt/api/res/1.2/I98BLf.EhcRpLI80gR0jrA--/YXBwaWQ9eW5ld3M7Zmk9aW5zZXQ7aD00MjA7cT04NTt3PTYzMA--/http://media.zenfs.com/en_us/News/gettyimages.com/diamond-jubilee-buckingham-palace-concert-20120604-162844-509.jpg" imageanchor="1" style="clear: left; float: left; margin-bottom: 1em; margin-right: 1em;"><img border="0" src="http://l3.yimg.com/bt/api/res/1.2/I98BLf.EhcRpLI80gR0jrA--/YXBwaWQ9eW5ld3M7Zmk9aW5zZXQ7aD00MjA7cT04NTt3PTYzMA--/http://media.zenfs.com/en_us/News/gettyimages.com/diamond-jubilee-buckingham-palace-concert-20120604-162844-509.jpg" height="131" width="200" /></a></div>\n<br />\nThe only other monarch in the histories of the Commonwealth realms having celebrated a Diamond Jubilee is Queen Victoria in 1897. The diamond jubilee tradition is to award Diamond Jubilee medals to various countries; holidays and events will be held throughout the Commonwealth. (FYI, the Big Ben will also be renamed to Elizabeth Tower to mark this celebration).<br />\n<br />\n<br />\n<br />\nThe Diamond Jubilee last week was just as huge and as spectacular as you may imagine. Union Jacks were everywhere; aircraft from the Battle of Britain (including Spitfires and a Hurricane) and the Red Arrows display team roared over the palace in a dramatic finale to the festivities, trailing red, white and blue smoke. Even me ( only watched the CNN Diamond Jubilee''s coverage from this other side of the world), could feel the enthusiasm and euphoria floating everywhere in the atmosphere. It was pompous!<br />\n<br />\n<br />\n<br />\n<br />\n<div style="text-align: left;">\nQueen Elizabeth smiled broadly and looked move by the scale of the tribute.</div>\n<br />\n<div class="separator" style="clear: both; text-align: center;">\n<a href="http://static.guim.co.uk/sys-images/Guardian/Pix/pictures/2012/6/2/1338666808179/Diamond-Jubilee---Epsom-D-008.jpg" imageanchor="1" style="clear: right; float: right; margin-bottom: 1em; margin-left: 1em;"><img border="0" src="http://static.guim.co.uk/sys-images/Guardian/Pix/pictures/2012/6/2/1338666808179/Diamond-Jubilee---Epsom-D-008.jpg" height="220" width="320" /></a></div>\n<span style="background-color: #ffe599;">"It has touched me deeply to see so many thousands of families, neighbors and friends celebrating together in such a happy atmosphere," she said, in a message recorded Monday at the palace.</span>\n<br />\n<span style="background-color: #ffe599;"><br /></span>\n<span style="background-color: #ffe599;">"I hope that memories of all this year''s happy events will brighten our lives for many years to come. I will continue to treasure and draw inspiration from the countless kindnesses shown to me from this country and throughout the Commonwealth. Thank you all."</span><br />\n<i>For the complete coverage on Queen''s Diamond Jubilee, click <a href="http://edition.cnn.com/SPECIALS/diamond-jubilee/index.html">here</a>.&nbsp;</i><br />\n<i><br /></i>\nWell, almost everyone cheered and had fun. Almost.<br />\nSome people talked about&nbsp;the monarchy only being little more than an anachronism in this 21st century. A ceremonial head of state, decided by blood?&nbsp;Some others talked about the cost, the cost of the monarchy (including this Diamond Jubilee''s celebration). One anti-monarchy group says that the Royals cost the British taxpayer more than £200 million ($320 million), according to AP reports. Even official estimates say that she costs £40 million a year.<br />\n&nbsp;<i>To see how exactly the Diamond Jubilee and the monarchy esp. Queen Elizabeth II cost so much click <a href="http://www.guardian.co.uk/uk/datablog/interactive/2012/may/30/queen-elizabeth-diamond-jubilee-interactive">here</a>.</i><br />\n<i><br /></i>\nQueen Elizabeth II, is by far the wealthiest royal in Britain, with an estimated next worth of $510 million.&nbsp;The top members of the British royal family are worth more than $1 billion. Compared to that, top soccer star David Beckham''s net worth reported to be $260 million. Even the value of the reigning soccer champions of England, Manchester City Football Club &nbsp;reportedly worth only $443 million. Wow.<br />\nHere is the <a href="http://www.businessinsider.com/infographic-the-british-royal-family-is-worth-more-than-1-billion-2012-6">infographic</a> from Wealth-X about top 14 &nbsp;royal line succession''s net worth.<br />\n<i><br /></i>\nDespise those facts and hatreds,a poll from this year found that 69% of those polled thought the UK would be worse off without the monarchy. Why British still love the Queen and the monarchy? This post is getting too long, I''ll post about it&nbsp;tomorrow&nbsp;on a new post. Come back!<br /><br />\n<div style="text-align: right;">\nto be continued...</div>\n<br />\n<br />\n<br />',
    'Being the head of The Commonwealth of Nations (also known as The British Commonwealth), the head of constitutional monarch of 16 sovereign states known as the Commonwealth realms, and also the head...',
    'It has touched me deeply to see so many thousands of families, neighbors and friends celebrating together in such a happy atmosphere," she said, in a message recorded Monday at the palace.',
    'perspective',
    ARRAY['monarchy', 'celebration', 'government', 'money', 'british', 'controversy', 'elizabeth II'],
    3,
    NULL,
    '{"image_url":"http://i.telegraph.co.uk/multimedia/archive/02207/qu_2207460b.jpg"}',
    false,
    false,
    true,
    '2012-06-07T15:38:00.001Z',
    '2012-06-07T14:01:30.324Z',
    '2017-06-02T05:59:02.749Z'
);

INSERT INTO posts (
    id, title, slug, content, excerpt, pull_quote, category, tags,
    read_time, issue, cover_art, text_only, featured, published,
    published_at, created_at, updated_at
) VALUES (
    'b69545f5-417f-481c-9e1c-d1b0e6befc42',
    'Why You Should Read Books',
    'why-you-should-read-books',
    '<div class="separator" style="clear: both; text-align: center;">\n<a href="http://www.ecorazzi.com/wp-content/uploads/2008/06/clooney.jpg" imageanchor="1" style="clear: right; float: right; margin-bottom: 1em; margin-left: 1em;"><img border="0" src="http://www.ecorazzi.com/wp-content/uploads/2008/06/clooney.jpg" height="215" width="320" /></a></div>\nThere are a lot of celebrities (maybe you are one of their fans) who like reading a lot. I''ve just come to recall &nbsp;this familiar name : Oprah Winfrey.<br />\n<br />\nSince her beginnings in a small town, Oprah has gone on to become one of the wealthiest women in the world, bringing her love of books with her. <a href="http://www.oprah.com/packages/oprahs-book-club-2.html">Her book club</a> has inspired millions of people around the world to read everything from new fiction to literary classics.<br />\n<br />\n<br />\nReading nourishes your mind, gives you both information and knowledge, and also encourages you to think and imagine.<br />\n<br />\nI cited this from Manali Oak &nbsp;:<br />\n<blockquote class="tr_bq">\n<i>Children who grow up reading good books, <span style="background-color: #f9cb9c;">definitely stand out</span>. <span style="background-color: #f9cb9c;">The way they think and act is way different from those who have never been exposed to reading</span>. Reading not only <span style="background-color: #f9cb9c;">adds to their general knowledge but also shapes their personalities</span>. If, during years of a child''s life, books become his companions, the child develops the hobby of reading and <span style="background-color: #f9cb9c;">grows up to be more versatile than he would have without reading</span>.&nbsp;</i></blockquote>\n<blockquote class="tr_bq">\n<i>Children who are introduced to reading at an early age are seen to have a<span style="background-color: #f9cb9c;"> better understanding of phonics</span>. They acquire language skills with ease, <span style="background-color: #f9cb9c;">have a richer vocabulary and possess greater cognitive abilities</span>. Reading helps develop creative and critical thinking skills. It develops vocabulary, sharpens language skills and leads to greater cognitive development. It leads to a better understanding of self.</i></blockquote>\nThe mind-expanding benefits are huge - and bear in mind that, while there’s a lot of great online reading, anything written by great thinkers in the past is often only available in books.<br />\n<br />\n<b>Vocabulary.&nbsp;</b><br />\nReading gives you richer vocabulary. If you can express yourself eloquently, the person hearing you has already decided you are intelligent. In most situations in life, intelligence will get you where you want to go. Sounding intelligent helps you on your path to that goal.<br />\n<br />\n<b>Imagination.</b><br />\nYou can imagine through watching tellies and playing computer games, you say ?&nbsp;TV and computer games have their place, but they are more like amusement. Amusement comes from two words "a" [non] and "muse" [think]. Amusement is <span style="background-color: #ffe599;">non-thinking</span> activities.<br />\n<blockquote class="tr_bq">\n<blockquote class="tr_bq">\nThink of the difference between watching television and reading a book. Watching television is, essentially, <b>a passive experience</b>. You sit, you look, and you listen. Such concentration as you have is driven by outside stimulation. In fact, when you are caught up in a TV show (or even a commercial, for that matter), it is a lot more like being hypnotized than being aware and present with your thoughts.</blockquote>\n<blockquote class="tr_bq">\nReading a book, on the other hand, <b>requires active concentration</b>. As you read, <i>you must put in a great deal of effort to look at the words, figure out what they mean, and build up images, thoughts and opinions within your mind. Moreover, if you are reading and you stop concentrating, even for a second, everything stops. Nothing happens until you start concentrating again.</i></blockquote>\n<blockquote class="tr_bq">\nFor this reason, reading regularly forces you to<span style="background-color: #ffe599;"> increase your powers of concentration</span>, a skill whose value would be difficult to overpraise.&nbsp;</blockquote>\n</blockquote>\n<br />\n<b>Information.</b><br />\nI don''t think I need to write long explanation for this. Everyone knows books contain so much information. <i>Knowledge is power!&nbsp;</i>Don’t dismiss fiction as a source of learning, either; you can earn lots of small things along the way: perhaps new words in a literary or classic novel, new facts in a historical novel, cultures, or new scientific information in a sci-fi novel. (My first introduction to English culture and history like in Old English, Medieval, Elizabethan, Victorian, and Renaissance age was through fiction books)<br />\n<br />\nWell, that''s all for now. If you really want to train your brain using books,&nbsp;I suggest you to read books that are just a bit harder than you can manage comfortably. Over time, as your mind develops, your ability to read and to think will grow.<br />\n<br />\n-Am I encountering words I don''t understand?<br />\n-Am I forced to stop once in a while to think carefully about what I am reading?<br />\n-Are there times when I must reread passages in order to understand them more clearly?<br />\n<br />\nIf the answers to these questions are no, you are not challenging yourself enough.<br />\n<br />\n<div style="text-align: center;">\n</div>\n<div style="text-align: center;">\n<span style="background-color: #fce5cd; font-size: large;">“To read is to fly: it is to soar to a point of vantage which gives a view over wide terrains of history, human variety, ideas, shared experience and the fruits of many inquiries.”&nbsp;</span></div>\n<div style="text-align: center;">\n<span style="background-color: #fce5cd;"><span style="font-size: large;">&nbsp;</span>- A C Grayling, Financial Times (in a review of A History of Reading by Alberto Manguel)</span></div>\n<br />\n<br />\n<br />\n<br />\n<br />\n<br />\n<br />',
    'There are a lot of celebrities (maybe you are one of their fans) who like reading a lot. I''ve just come to recall &nbsp;this familiar name : Oprah Winfrey.',
    'you must put in a great deal of effort to look at the words, figure out what they mean, and build up images, thoughts and opinions within your mind. Moreover, if you are reading and you stop concentrating, even for a second, everything stops. Nothing happens until you start concentrating again.',
    'perspective',
    ARRAY['entertainment', 'book'],
    4,
    NULL,
    '{"image_url":"http://www.ecorazzi.com/wp-content/uploads/2008/06/clooney.jpg"}',
    false,
    false,
    true,
    '2012-06-06T07:56:00.001Z',
    '2012-06-05T15:09:53.398Z',
    '2017-06-02T05:57:55.037Z'
);

INSERT INTO posts (
    id, title, slug, content, excerpt, pull_quote, category, tags,
    read_time, issue, cover_art, text_only, featured, published,
    published_at, created_at, updated_at
) VALUES (
    '8dfe2744-b89a-451b-8b19-ddbb93c7eb3b',
    'Leaders'' Pay Cuts',
    'leaders-pay-cuts',
    '<div class="separator" style="clear: both; text-align: center;">\n</div>\nNot so long ago, French have just got new faces in their government.&nbsp;François Hollande was elected President of France on 6 May 2012 then appointed Jean-Marc Ayrault to be his Prime Minister shortly afterwards.<br />\n<br />\n<a href="http://news.bbcimg.co.uk/media/images/60254000/jpg/_60254704_014752679-1.jpg" imageanchor="1" style="clear: left; float: left; margin-bottom: 1em; margin-right: 1em;"><img border="0" height="320" src="http://news.bbcimg.co.uk/media/images/60254000/jpg/_60254704_014752679-1.jpg" width="240" /></a>Marking his&nbsp;debut, one of his policies in first cabinet meeting was to cut his own and his cabinet pay by 30%.<br />\nThe policy knocked the wage Hollande will earn to just under 15,000 euros (14,910 euros from 21,300 euros) a month.&nbsp;This contrasts sharply with predecessor Nicolas Sarkozy''s decision to increase his pay on entering office (I find this kinda funny).<br />\n<br />\nIt was (and still is) a stormy start for&nbsp;François Hollande;&nbsp;everyone knows France is in a depressing state. Everyone knows that there is more discomfort to come.&nbsp;All that can be hoped for is slow, methodical crisis management. The dreaming time is over.<br />\n<br />\nIf you keep up with the news, after his celebration speech of becoming the new France''s president, the jet taking him to Germany had been struck by lightning. In addition, Mr Hollande also got a soaking at the tomb of the Unknown Soldier at the Arc de Triomphe in Paris. Lets just hope he is not a&nbsp;superstitious person, since there are too many bad signs on his first days as the new president.<br />\n<br />\nBut what I want to point out here is not how he seems to be a friend of bad luck, it''s about his pay cut policy.&nbsp;With a debt crisis again rumbling louder in the euro zone, &nbsp;he said&nbsp;"We''re convinced public debt is an enemy for the country. Our task will be reducing deficits and debt … this is the task we will address first" then took that policy to at least reduce the government''s outcome and to show that they are sharing the hard times facing the country. It''s somehow seems impossible for our government, here in Indonesia, to do the same thing.<br />\n<br />\nIndonesian government seems to raise the government''s outcome a lot over trivial things like toilets renovation for over 2 billion rupiah, DPR new building, and also the monorail project (which is really a waste of money since it''s cancelled at the end). Why don''t we take examples from Mr. Hollande? Even though his pay cut won''t simply release France from its financial crisis, at least people know he is eager to sacrifice for the sake of his country. He wanted to struggle together with his citizens. Here in Indonesia (which is also having a lot of debts), there are a lot of people struggling out there for money. Why can''t our government show them a little bit of concern ?<br />\n<br />\nHere I put a video of another leader cutting his own pay : the CEO of Japanese Airline Company. He pays himself &nbsp;LESS than his regular pilots. Both&nbsp;\nFrançois Hollande&nbsp;and&nbsp;Naruka Nishimatsu (the JAL CEO), what a great leader examples they are, aren''t they ?<br />\n<br />\n<br />\n<br />\n<br />\n<br />\n<center>\n<iframe allowfullscreen="" frameborder="0" height="315" src="http://www.youtube.com/embed/AqFxK3GMEkA" width="420"></iframe></center>\n<br />\n<br />\nI''ll cite a comment from Youtube on this video :<br />\n<blockquote class="tr_bq">\n<span style="background-color: #ebebeb; color: #333333; font-family: arial, sans-serif; font-size: 13px; line-height: 16px; text-align: left;">Slashes his own pay , eats with his co-workers and saving the jobs with his selfless act - He sets a standards not﻿ only to the other CEOs across the globe but also politicians and other dudes at the top whom is pocketing a whole lot of cash into their wallets in disregard to the others.</span>\n</blockquote>\n<blockquote class="tr_bq">\n<br /></blockquote>\n',
    'Not so long ago, French have just got new faces in their government.&nbsp;François Hollande was elected President of France on 6 May 2012 then appointed Jean-Marc Ayrault to be his Prime Minister...',
    'Slashes his own pay , eats with his co-workers and saving the jobs with his selfless act - He sets a standards not only to the other CEOs across the globe but also politicians and other dudes at the top whom is pocketing a whole lot of cash into their wallets in disregard to the others.',
    'others',
    ARRAY['government', 'money', 'role model'],
    3,
    NULL,
    '{"image_url":"http://news.bbcimg.co.uk/media/images/60254000/jpg/_60254704_014752679-1.jpg"}',
    false,
    false,
    true,
    '2012-06-05T09:44:00Z',
    '2012-06-05T08:08:18.733Z',
    '2012-12-25T10:44:23.384Z'
);

INSERT INTO posts (
    id, title, slug, content, excerpt, pull_quote, category, tags,
    read_time, issue, cover_art, text_only, featured, published,
    published_at, created_at, updated_at
) VALUES (
    '3338e184-3102-434d-9916-e9f12985d141',
    'Blogging with Your iPad',
    'blogging-with-your-ipad',
    'My own review of best app on iPad for blogging :)<br />\n<div>\n<br /></div>\n<div>\n<br /></div>\n<div style="text-align: left;">\n<b><u><span style="background-color: #f4cccc; font-size: large;">Blogsy</span></u></b></div>\n<div style="text-align: left;">\n<b><u><br /></u></b></div>\n<div class="separator" style="clear: both; text-align: center;">\n</div>\n<div>\n<div style="text-align: justify;">\nBlogsy is a paid app at a reasonable price (US $4.99).&nbsp;It''s kinda hard to use it well for the first time since it has so many features; you have to read/ watch the tutorial for a better and more thorough understanding. It does have a steeper learning curve, but you can get more advanced formatting options and functionality.</div>\n</div>\n<div>\n<div style="text-align: justify;">\n<br /></div>\n<div style="text-align: justify;">\nWith Blogsy, it doesn''t take much more than dragging and dropping images/videos to get them aligned and sized just right. You can also edit your post using the HTML code editor.</div>\n</div>\n<div>\n<div style="text-align: justify;">\n<br /></div>\n</div>\n<div>\n<div style="text-align: justify;">\nIn addition, compared to others, Blogsy''s preview presents the most accurate picture of what your published posts will look like. Blogsy currently supports Wordpress, Blogger, Posterous, TypePad, Movable Type, Joomla, Drupal, IBM Connections, and also Tumblr. If you blog to a platform not listed above, Blogsy allows you to make rich emails and post them to your blog (of course only if your blog supports email posting)</div>\n<div style="text-align: justify;">\n<br /></div>\n<div style="text-align: justify;">\np.s. If you have any question regarding Blogsy, the developers are really quick to respond. Just ask them through email/Twitter :)</div>\n<br />\n<a href="http://blogsyapp.com/">Blogsy website</a></div>\n<div>\n<a href="http://itunes.apple.com/us/app/blogsy/id428485324?mt=8">Blogsy on iTunes</a></div>\n<div>\n<br /></div>\n<div>\n<br /></div>\n<div>\n<br /></div>\n<div>\n<div style="text-align: left;">\n<u><b><span style="background-color: #f4cccc; font-size: large;">BlogPress</span></b></u></div>\n<div style="text-align: center;">\n<u><b><br /></b></u></div>\n<div class="separator" style="clear: both; text-align: left;">\n</div>\n<div style="text-align: center;">\n<div style="text-align: justify;">\n<span style="text-align: left;">BlogPress is an easy to use application with simple formatting options. It also costs US $4.99 like Blogsy, but it works on iPod Touch and iPhone too. There is a way to see comments on your post within this app.&nbsp;It''s not as slick as Blogsy, I don''t think the image editor will please you, but it''s better for those who don''t have much time to learn. BlogPress also supports greater number of blog : Blogger, MSN Live Spaces, WordPress, Movable Type, TypePad , LiveJournal, Drupal, Joomla, Tumblr, Squarespace, My Opera&nbsp;</span></div>\n</div>\n<div style="text-align: left;">\n<br /></div>\n<div style="text-align: left;">\n<a href="http://blogpressapp.com/">BlogPress website</a></div>\n<div style="text-align: left;">\n<a href="http://itunes.apple.com/us/app/blogpress/id317799861?mt=8">BlogPress on iTunes</a><br />\n<br />\n<br />\n<br />\n<br />\n<br />\n<br />\n<br />\n<br />\n<br />\n<br />\n<br />\n<span style="font-size: large;"><b><u style="background-color: #f4cccc;">WordPress</u></b></span><br />\n<div class="separator" style="clear: both; text-align: center;">\n</div>\nWordPress is <span style="background-color: #fff2cc;">FREE</span>, but it''s limited and &nbsp;buggy. It''s compatible with iPhone, iPod Touch, and iPad. This app has a push notification feature for new comments.&nbsp;Personally I don''t like this app, you need to write your own HTML code. It''s an opensource project anyway, so let''s just hope for improvements, haha.<br />\n<br />\n<a href="http://ios.wordpress.org/">WordPress website</a><br />\n<a href="http://itunes.apple.com/us/app/wordpress/id335703880?mt=8">WordPress on iTunes</a><br />\n<br />\n<br />\n<br />\n<br />\n<br />\n<br />\n<br />\nBesides those three apps, there are some more blogging apps tailored to iPad such as BloggerPlus and BlogWriter. Here is the quick comparison between them all :<br />\n<br />\n<div class="separator" style="clear: both; text-align: center;">\n<a href="http://theedublogger.com/files/2011/06/app41-s8dy13.jpg" imageanchor="1" style="margin-left: 1em; margin-right: 1em;"><img border="0" src="http://theedublogger.com/files/2011/06/app41-s8dy13.jpg" height="336" width="400" /></a></div>\n<div class="separator" style="clear: both; text-align: center;">\n<br /></div>\n<div class="separator" style="clear: both; text-align: center;">\n<br /></div>\n<div class="separator" style="clear: both; text-align: left;">\nIf you blog regularly, I recommend you to spend some money for Blogsy. It''s by far the best blogging application I know.&nbsp;</div>\n<br />\n<br /></div>\n</div>\n',
    'My own review of best app on iPad for blogging :) Blogsy Blogsy is a paid app at a reasonable price (US $4.99).&nbsp;It''s kinda hard to use it well for the first time since it has so many features;...',
    NULL,
    'others',
    ARRAY['technology', 'ipad', 'application', 'blog', 'review'],
    3,
    NULL,
    '{"image_url":"http://theedublogger.com/files/2011/06/app41-s8dy13.jpg"}',
    false,
    false,
    true,
    '2012-05-28T13:17:00.004Z',
    '2012-05-28T11:24:20.374Z',
    '2017-06-02T04:59:29.489Z'
);

INSERT INTO posts (
    id, title, slug, content, excerpt, pull_quote, category, tags,
    read_time, issue, cover_art, text_only, featured, published,
    published_at, created_at, updated_at
) VALUES (
    'acdf7ad8-b6c8-40c5-a7e4-ea6a807e636f',
    'First Post',
    'first-post',
    '<div class="separator" style="clear: both; text-align: center;">\n</div>\nI would like to say&nbsp;&nbsp;<span style="background-color: #fff2cc;">welcome</span>&nbsp;and&nbsp;<span style="background-color: #fff2cc;">thank you</span>&nbsp;for&nbsp;visiting my new blog!<br />\n<br />\nAs you (may) know, I have another blog created since 2008 which is mostly about my embarrassing puberty. I deleted that one since I''m so ashamed of it hahaha. It''s kinda sad for me to leave the old blog and start a new one (0 page view !), my previous blog was kinda popular back then in my high school, it was like an unofficial school magazine.&nbsp;BUT, I intend to read it again maybe in 10 years later as a laughing stock so I have saved those blog posts for myself.<br />\n<br />\nWhat''s new? I''ve started working full time since my 2nd semester in university and done some freelance jobs as well. Even though I''ve been working as a translator since high school, this is on a completely new level for me. I''m trying to be more responsible by paying my tuition fee, etc. It''s not like my family is in economic breakdown or whatever, but yeah I just want my parents to know that they have nurtured me correctly, haha. I bought an iPhone and iPad with my own money and it feels so good! A few years back it''s already torturing for me to buy books with my own money xD<br />\n<br />\nAH, since I can''t have a dog so I now join some animal charity organizations and they are uber cool. We rescued animals during the big flood in Pluit and I''ve never felt that good in my life. It''s like a different kind of good. I wonder if I have the superhero syndrome but I took the test and it says no haha. So, we indeed make a living by what we get, and we make a life by what we give :)<br />\n<br />\nCome to think of it, there''s not a single day in life that shouldn''t be thanked for; even some bad days are meant to be thanked for. It''s all good to me. Life is good. I want to send a message to my future self: Don''t EVER wish away your days, just don''t. AND STOP BEING OBSESSED WITH EVERYTHING!!! Seriously I''m either profoundly obsessed or not giving a fuck at all. There''s no in between. I feel crazy.<br />\n<br />\nAnyway, visit my blog often! I''m out!!!<br />\n<div class="separator" style="clear: both; text-align: center;">\n<br /></div>\n',
    'I would like to say&nbsp;&nbsp; welcome &nbsp;and&nbsp; thank you &nbsp;for&nbsp;visiting my new blog!',
    NULL,
    'personal',
    ARRAY['personal'],
    3,
    NULL,
    '{"p1":"#6f9bd1","p2":"#c08a64"}',
    false,
    false,
    true,
    '2012-05-15T15:43:00Z',
    '2012-05-15T14:44:21.455Z',
    '2017-06-02T05:55:59.078Z'
);

